func TestComponent_HierarchyInference_LifecycleIntegration(t *testing.T) {
	tests := []struct {
		name                  string
		enableHierarchy       bool
		expectHierarchyActive bool
	}{
		{
			name:                  "hierarchy enabled - inference should start",
			enableHierarchy:       true,
			expectHierarchyActive: true,
		},
		{
			name:                  "hierarchy disabled - inference should not start",
			enableHierarchy:       false,
			expectHierarchyActive: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// This test verifies that:
			// 1. When component starts with enable_hierarchy: true, HierarchyInference is created and started
			// 2. When component stops, HierarchyInference is also stopped
			// 3. When enable_hierarchy: false, HierarchyInference is not active

			comp := createTestComponentWithHierarchyConfig(t, tt.enableHierarchy)
			ctx := context.Background()

			require.NoError(t, comp.Initialize())

			// Component should have hierarchy inference field accessible
			// Builder must add hierarchyInference field to Component struct
			// This test will fail until Builder implements the integration

			// Start component
			err := comp.Start(ctx)
			require.NoError(t, err)
			defer comp.Stop(5 * time.Second)

			// Allow time for hierarchy inference to start watching
			time.Sleep(200 * time.Millisecond)

			// Verify hierarchy inference is active when enabled
			if tt.expectHierarchyActive {
				// When hierarchy is enabled and component is running,
				// the hierarchy inference watcher should be active.
				// Builder must verify this by checking internal state or metrics.

				// Test by creating an entity and checking if containers are created
				entity := &graph.EntityState{
					ID: "c360.platform.robotics.mav1.drone.test001",
					Triples: []message.Triple{
						{
							Subject:   "c360.platform.robotics.mav1.drone.test001",
							Predicate: "entity.type.class",
							Object:    "robotics.drone",
							Timestamp: time.Now(),
						},
					},
					Version:   1,
					UpdatedAt: time.Now(),
				}

				require.NoError(t, comp.CreateEntity(ctx, entity))

				// Allow time for hierarchy inference to process
				time.Sleep(300 * time.Millisecond)

				// Verify containers were created
				containerIDs := []string{
					"c360.platform.robotics.mav1.drone.group",      // Type container
					"c360.platform.robotics.mav1.group.container",  // System container
					"c360.platform.robotics.group.container.level", // Domain container
				}

				for _, containerID := range containerIDs {
					entry, err := comp.entityBucket.Get(ctx, containerID)
					assert.NoError(t, err, "container %s should exist", containerID)
					if entry != nil {
						var containerEntity graph.EntityState
						err = json.Unmarshal(entry.Value(), &containerEntity)
						assert.NoError(t, err)
						assert.Equal(t, containerID, containerEntity.ID)
					}
				}
			} else {
				// When hierarchy is disabled, no containers should be created
				entity := &graph.EntityState{
					ID: "c360.platform.robotics.mav1.drone.test002",
					Triples: []message.Triple{
						{
							Subject:   "c360.platform.robotics.mav1.drone.test002",
							Predicate: "entity.type.class",
							Object:    "robotics.drone",
							Timestamp: time.Now(),
						},
					},
					Version:   1,
					UpdatedAt: time.Now(),
				}

				require.NoError(t, comp.CreateEntity(ctx, entity))

				// Allow time (nothing should happen)
				time.Sleep(300 * time.Millisecond)

				// Verify containers were NOT created
				containerIDs := []string{
					"c360.platform.robotics.mav1.drone.group",
					"c360.platform.robotics.mav1.group.container",
					"c360.platform.robotics.group.container.level",
				}

				for _, containerID := range containerIDs {
					_, err := comp.entityBucket.Get(ctx, containerID)
					assert.ErrorIs(t, err, jetstream.ErrKeyNotFound, "container %s should not exist when hierarchy disabled", containerID)
				}
			}

			// Stop component
			err = comp.Stop(5 * time.Second)
			assert.NoError(t, err)

			// After stop, hierarchy inference should be stopped
			// Builder must ensure HierarchyInference.Stop() is called in Component.Stop()
		})
	}
}

