func TestComponent_HierarchyInference_StopCleanup(t *testing.T) {
	comp := createTestComponentWithHierarchyConfig(t, true)
	ctx := context.Background()

	require.NoError(t, comp.Initialize())
	require.NoError(t, comp.Start(ctx))

	// Allow hierarchy inference to start
	time.Sleep(200 * time.Millisecond)

	// Create entity to verify hierarchy is working
	entity := &graph.EntityState{
		ID: "c360.platform.robotics.mav1.drone.test001",
		Triples: []message.Triple{
			{
				Subject:   "c360.platform.robotics.mav1.drone.test001",
				Predicate: "entity.type.class",
				Object:    "robotics.drone",
				Timestamp: time.Now(),
			},
		},
		Version:   1,
		UpdatedAt: time.Now(),
	}

	require.NoError(t, comp.CreateEntity(ctx, entity))

	// Allow time for hierarchy inference to process
	time.Sleep(300 * time.Millisecond)

	// Verify container was created (hierarchy is active)
	containerID := "c360.platform.robotics.mav1.drone.group"
	entry, err := comp.entityBucket.Get(ctx, containerID)
	require.NoError(t, err, "container should exist before stop")
	assert.NotNil(t, entry)

	// Stop component
	err = comp.Stop(5 * time.Second)
	assert.NoError(t, err, "component should stop gracefully")

	// After stop, hierarchy inference should be stopped
	// Builder must ensure HierarchyInference.Stop() is called in Component.Stop()
	// This prevents:
	// 1. Goroutine leaks from watcher
	// 2. Continued processing after component shutdown
	// 3. Resource leaks

	// Verify no new entities trigger hierarchy after stop
	entity2 := &graph.EntityState{
		ID: "c360.platform.robotics.mav1.drone.test002",
		Triples: []message.Triple{
			{
				Subject:   "c360.platform.robotics.mav1.drone.test002",
				Predicate: "entity.type.class",
				Object:    "robotics.drone",
				Timestamp: time.Now(),
			},
		},
		Version:   1,
		UpdatedAt: time.Now(),
	}

	// CreateEntity should fail or not trigger hierarchy after stop
	err = comp.CreateEntity(ctx, entity2)
	// Either error (component stopped) or success but no hierarchy processing
	if err == nil {
		// If CreateEntity succeeds, verify no hierarchy processing occurred
		time.Sleep(300 * time.Millisecond)

		// Entity should not have membership edges added after component stop
		entry, err := comp.entityBucket.Get(ctx, entity2.ID)
		if err == nil {
			var stoppedEntity graph.EntityState
			err = json.Unmarshal(entry.Value(), &stoppedEntity)
			if err == nil {
				// Count hierarchy edges
				hierarchyEdgeCount := 0
				for _, triple := range stoppedEntity.Triples {
					if triple.Context == "inference.hierarchy" {
						hierarchyEdgeCount++
					}
				}
				assert.Equal(t, 0, hierarchyEdgeCount, "no hierarchy edges should be added after component stop")
			}
		}
	}
}

